133→  period: string;
134→  views: number;
135→  uniqueVisitors: number;
136→  sales: number;
137→  revenue: number;
138→  conversionRate: number;
139→  topProducts: { name: string; sales: number; revenue: number }[];
140→  trafficSources: { source: string; visits: number; percentage: number }[];
