 1→import React from 'react';
 2→
 3→interface Column<T> {
 4→  key: string;
 5→  label: string;
 6→  render?: (value: unknown, row: T, index: number) => React.ReactNode;
 7→}
 8→
 9→interface DataTableProps<T extends Record<string, unknown>> {
10→  columns: Column<T>[];
11→  data: T[];
12→  onRowClick?: (row: T, index: number) => void;
13→  className?: string;
14→}
15→
16→export function DataTable<T extends Record<string, unknown>>({
17→  columns,
18→  data,
19→  onRowClick,
20→  className = '',
21→}: DataTableProps<T>) {
22→  return (
23→    <div
24→      className={`
25→        overflow-x-auto border border-[var(--border-default)] rounded-xl
26→        ${className}
27→      `.trim()}
28→    >
29→      <table className="w-full text-sm">
30→        <thead>
31→          <tr className="border-b border-[var(--border-default)]">
32→            {columns.map((col) => (
33→              <th
34→                key={col.key}
35→                className="px-4 py-3 text-left text-xs font-medium text-[var(--text-secondary)] uppercase tracking-wider bg-[var(--bg-elevated)]"
36→              >
37→                {col.label}
38→              </th>
39→            ))}
40→          </tr>
41→        </thead>
42→        <tbody>
43→          {data.map((row, rowIndex) => (
44→            <tr
45→              key={rowIndex}
46→              className={`
47→                border-b border-[var(--border-default)] last:border-b-0
48→                ${rowIndex % 2 === 1 ? 'bg-[var(--bg-elevated)]' : 'bg-[var(--bg-surface)]'}
49→                ${onRowClick ? 'cursor-pointer hover:bg-[var(--bg-elevated)]' : ''}
50→                transition-colors duration-100
51→              `.trim()}
52→              onClick={onRowClick ? () => onRowClick(row, rowIndex) : undefined}
53→            >
54→              {columns.map((col) => (
55→                <td
56→                  key={col.key}
57→                  className="px-4 py-3 text-[var(--text-primary)] whitespace-nowrap"
58→                >
59→                  {col.render
60→                    ? col.render(row[col.key], row, rowIndex)
61→                    : (row[col.key] as React.ReactNode)}
62→                </td>
63→              ))}
64→            </tr>
65→          ))}
66→
67→          {data.length === 0 && (
68→            <tr>
69→              <td
70→                colSpan={columns.length}
71→                className="px-4 py-12 text-center text-[var(--text-secondary)]"
72→              >
73→                No data available
74→              </td>
75→            </tr>
76→          )}
77→        </tbody>
78→      </table>
79→    </div>
80→  );
81→}
82→

 1→import React from 'react';
 2→
 3→interface Tab {
 4→  id: string;
 5→  label: string;
 6→}
 7→
 8→interface TabsProps {
 9→  tabs: Tab[];
10→  activeTab: string;
11→  onChange: (tabId: string) => void;
12→  className?: string;
13→}
14→
15→export function Tabs({ tabs, activeTab, onChange, className = '' }: TabsProps) {
16→  return (
17→    <div
18→      className={`
19→        flex gap-1 border-b border-[var(--border-default)]
20→        ${className}
21→      `.trim()}
22→      role="tablist"
23→    >
24→      {tabs.map((tab) => {
25→        const isActive = tab.id === activeTab;
26→
27→        return (
28→          <button
29→            key={tab.id}
30→            role="tab"
31→            aria-selected={isActive}
32→            onClick={() => onChange(tab.id)}
33→            className={`
34→              relative px-4 py-2.5 text-sm font-medium transition-colors duration-150
35→              ${
36→                isActive
37→                  ? 'text-[var(--accent)]'
38→                  : 'text-[var(--text-secondary)] hover:text-[var(--text-primary)]'
39→              }
40→            `.trim()}
41→          >
42→            {tab.label}
43→            {isActive && (
44→              <span className="absolute bottom-0 left-0 right-0 h-0.5 bg-[var(--accent)] rounded-full" />
45→            )}
46→          </button>
47→        );
48→      })}
49→    </div>
50→  );
51→}
