import React from 'react';
import {
  DollarSign,
  ShoppingCart,
  Package,
  Users,
  Plus,
  Send,
  ExternalLink,
  TrendingUp,
} from 'lucide-react';
import {
  AreaChart,
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
} from 'recharts';
import { StatsCard } from '../components/ui/StatsCard';
import { Card } from '../components/ui/Card';
import { Badge } from '../components/ui/Badge';
import { Button } from '../components/ui/Button';
import { DataTable } from '../components/ui/DataTable';
import { demoOrders, demoAnalytics } from '../lib/demo-data';
import type { Order } from '../types';

const statusVariant: Record<Order['status'], 'success' | 'error' | 'warning' | 'default'> = {
  completed: 'success',
  refunded: 'error',
  pending: 'warning',
  failed: 'default',
};

const recentOrders = demoOrders.slice(0, 5);

const orderColumns = [
  {
    key: 'id',
    label: 'Order',
    render: (value: unknown) => (
      <span className="font-medium text-[var(--text-primary)]">
        {String(value)}
      </span>
    ),
  },
  {
    key: 'customerName',
    label: 'Customer',
    render: (_value: unknown, row: Record<string, unknown>) => (
      <div>
        <p className="font-medium text-[var(--text-primary)]">
          {String(row.customerName)}
        </p>
        <p className="text-xs text-[var(--text-secondary)]">
          {String(row.customerEmail)}
        </p>
      </div>
    ),
  },
  {
    key: 'productTitle',
    label: 'Product',
    render: (value: unknown) => (
      <span className="text-[var(--text-primary)] max-w-[200px] truncate block">
        {String(value)}
      </span>
    ),
  },
  {
    key: 'amount',
    label: 'Amount',
    render: (_value: unknown, row: Record<string, unknown>) => (
      <span className="font-semibold text-[var(--text-primary)]">
        ${Number(row.amount).toFixed(2)}
      </span>
    ),
  },
  {
    key: 'status',
    label: 'Status',
    render: (value: unknown) => {
      const status = String(value) as Order['status'];
      return (
        <Badge variant={statusVariant[status]}>
          {status.charAt(0).toUpperCase() + status.slice(1)}
        </Badge>
      );
    },
  },
  {
    key: 'createdAt',
    label: 'Date',
    render: (value: unknown) => {
      const date = new Date(String(value));
      return (
        <span className="text-[var(--text-secondary)]">
          {date.toLocaleDateString('en-US', {
            month: 'short',
            day: 'numeric',
            year: 'numeric',
          })}
        </span>
      );
    },
  },
];

const chartData = demoAnalytics.dailyData.map((d) => ({
  ...d,
  date: new Date(d.date).toLocaleDateString('en-US', {
    month: 'short',
    day: 'numeric',
  }),
}));

export default function Dashboard() {
  return (
    <div className="page-enter space-y-6">
      {/* Header */}
      <div>
        <h1 className="text-2xl font-bold text-[var(--text-primary)]">
          Dashboard
        </h1>
        <p className="text-[var(--text-secondary)] mt-1">
          Welcome back, Sarah
        </p>
      </div>

      {/* Stats Row */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
        <StatsCard
          label="Total Revenue"
          value="$43,512"
          change={12.5}
          changeLabel="vs last month"
          icon={<DollarSign className="w-5 h-5" />}
        />
        <StatsCard
          label="Sales"
          value="820"
          change={8.3}
          changeLabel="vs last month"
          icon={<ShoppingCart className="w-5 h-5" />}
        />
        <StatsCard
          label="Active Products"
          value="5"
          icon={<Package className="w-5 h-5" />}
        />
        <StatsCard
          label="Subscribers"
          value="1,580"
          icon={<Users className="w-5 h-5" />}
        />
      </div>

      {/* Revenue Chart */}
      <Card padding="md">
        <div className="flex items-center justify-between mb-4">
          <div>
            <h2 className="text-lg font-semibold text-[var(--text-primary)]">
              Revenue
            </h2>
            <p className="text-sm text-[var(--text-secondary)]">
              Last 14 days
            </p>
          </div>
          <div className="flex items-center gap-2 text-sm text-[var(--text-secondary)]">
            <TrendingUp className="w-4 h-4 text-emerald-500" />
            <span className="text-emerald-500 font-medium">+12.5%</span>
          </div>
        </div>
        <div className="h-[280px] w-full">
          <ResponsiveContainer width="100%" height="100%">
            <AreaChart
              data={chartData}
              margin={{ top: 5, right: 10, left: 0, bottom: 0 }}
            >
              <defs>
                <linearGradient id="revenueGradient" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="var(--accent)" stopOpacity={0.2} />
                  <stop offset="95%" stopColor="var(--accent)" stopOpacity={0} />
                </linearGradient>
              </defs>
              <CartesianGrid
                strokeDasharray="3 3"
                stroke="var(--border-default)"
                vertical={false}
              />
              <XAxis
                dataKey="date"
                tick={{ fill: 'var(--text-secondary)', fontSize: 12 }}
                tickLine={false}
                axisLine={{ stroke: 'var(--border-default)' }}
              />
              <YAxis
                tick={{ fill: 'var(--text-secondary)', fontSize: 12 }}
                tickLine={false}
                axisLine={false}
                tickFormatter={(v: number) => `$${v}`}
              />
              <Tooltip
                contentStyle={{
                  backgroundColor: 'var(--bg-surface)',
                  border: '1px solid var(--border-default)',
                  borderRadius: '8px',
                  boxShadow: '0 4px 12px rgba(0,0,0,0.1)',
                  color: 'var(--text-primary)',
                }}
                labelStyle={{ color: 'var(--text-secondary)', marginBottom: 4 }}
                formatter={(value: number) => [`$${value}`, 'Revenue']}
              />
              <Area
                type="monotone"
                dataKey="revenue"
                stroke="var(--accent)"
                strokeWidth={2}
                fill="url(#revenueGradient)"
              />
            </AreaChart>
          </ResponsiveContainer>
        </div>
      </Card>

      {/* Two Column: Recent Orders + Top Products */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Recent Orders */}
        <div className="lg:col-span-2">
          <div className="flex items-center justify-between mb-4">
            <h2 className="text-lg font-semibold text-[var(--text-primary)]">
              Recent Orders
            </h2>
            <Button variant="ghost" size="sm">
              View All
            </Button>
          </div>
          <DataTable
            columns={orderColumns}
            data={recentOrders as unknown as Record<string, unknown>[]}
          />
        </div>

        {/* Top Products */}
        <div>
          <h2 className="text-lg font-semibold text-[var(--text-primary)] mb-4">
            Top Products
          </h2>
          <div className="space-y-3">
            {demoAnalytics.topProducts.map((product, index) => (
              <Card key={index} padding="sm" hover>
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-3 min-w-0">
                    <div className="w-8 h-8 rounded-lg bg-[var(--accent-subtle)] flex items-center justify-center shrink-0">
                      <span className="text-sm font-bold text-[var(--accent)]">
                        {index + 1}
                      </span>
                    </div>
                    <div className="min-w-0">
                      <p className="text-sm font-medium text-[var(--text-primary)] truncate">
                        {product.name}
                      </p>
                      <p className="text-xs text-[var(--text-secondary)]">
                        {product.sales} sales
                      </p>
                    </div>
                  </div>
                  <span className="text-sm font-semibold text-[var(--text-primary)] shrink-0 ml-3">
                    ${product.revenue.toLocaleString()}
                  </span>
                </div>
              </Card>
            ))}
          </div>
        </div>
      </div>

      {/* Quick Actions */}
      <Card padding="md">
        <h2 className="text-lg font-semibold text-[var(--text-primary)] mb-4">
          Quick Actions
        </h2>
        <div className="flex flex-wrap gap-3">
          <Button variant="primary" icon={<Plus className="w-4 h-4" />}>
            Add Product
          </Button>
          <Button variant="secondary" icon={<Send className="w-4 h-4" />}>
            Send Broadcast
          </Button>
          <Button
            variant="secondary"
            icon={<ExternalLink className="w-4 h-4" />}
            iconPosition="right"
          >
            View Store
          </Button>
        </div>
      </Card>
    </div>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Plus,
  Search,
  ChevronDown,
  FileText,
  GraduationCap,
  Calendar,
  Crown,
  Video,
  Link2,
  BarChart3,
  DollarSign,
} from 'lucide-react';
import { Button } from '../components/ui/Button';
import { Card } from '../components/ui/Card';
import { Badge } from '../components/ui/Badge';
import { Tabs } from '../components/ui/Tabs';
import { Toggle } from '../components/ui/Toggle';
import { demoProducts } from '../lib/demo-data';
import type { ProductType, Product } from '../types';

const productTabs = [
  { id: 'all', label: 'All' },
  { id: 'digital', label: 'Digital' },
  { id: 'course', label: 'Course' },
  { id: 'booking', label: 'Booking' },
  { id: 'membership', label: 'Membership' },
  { id: 'webinar', label: 'Webinar' },
];

const sortOptions = [
  { value: 'newest', label: 'Newest' },
  { value: 'best-selling', label: 'Best Selling' },
  { value: 'price-high', label: 'Price: High to Low' },
  { value: 'price-low', label: 'Price: Low to High' },
];

const typeIcons: Record<ProductType, React.ElementType> = {
  digital: FileText,
  course: GraduationCap,
  booking: Calendar,
  membership: Crown,
  webinar: Video,
  link: Link2,
  custom: BarChart3,
};

const typeColors: Record<ProductType, string> = {
  digital: 'bg-blue-500/10 text-blue-600',
  course: 'bg-purple-500/10 text-purple-600',
  booking: 'bg-amber-500/10 text-amber-600',
  membership: 'bg-emerald-500/10 text-emerald-600',
  webinar: 'bg-rose-500/10 text-rose-600',
  link: 'bg-cyan-500/10 text-cyan-600',
  custom: 'bg-gray-500/10 text-gray-600',
};

const typeBadgeColors: Record<ProductType, string> = {
  digital: 'bg-blue-500/10 text-blue-600 border-blue-500/20',
  course: 'bg-purple-500/10 text-purple-600 border-purple-500/20',
  booking: 'bg-amber-500/10 text-amber-600 border-amber-500/20',
  membership: 'bg-emerald-500/10 text-emerald-600 border-emerald-500/20',
  webinar: 'bg-rose-500/10 text-rose-600 border-rose-500/20',
  link: 'bg-cyan-500/10 text-cyan-600 border-cyan-500/20',
  custom: 'bg-gray-500/10 text-gray-600 border-gray-500/20',
};

function sortProducts(products: Product[], sortBy: string): Product[] {
  const sorted = [...products];
  switch (sortBy) {
    case 'newest':
      return sorted.sort(
        (a, b) =>
          new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
      );
    case 'best-selling':
      return sorted.sort((a, b) => b.salesCount - a.salesCount);
    case 'price-high':
      return sorted.sort((a, b) => b.price - a.price);
    case 'price-low':
      return sorted.sort((a, b) => a.price - b.price);
    default:
      return sorted;
  }
}

export default function AllProducts() {
  const [activeTab, setActiveTab] = useState('all');
  const [search, setSearch] = useState('');
  const [sortBy, setSortBy] = useState('newest');
  const [publishedState, setPublishedState] = useState<Record<string, boolean>>(
    () => {
      const state: Record<string, boolean> = {};
      demoProducts.forEach((p) => {
        state[p.id] = p.published;
      });
      return state;
    }
  );
  const [sortOpen, setSortOpen] = useState(false);

  const filteredProducts = useMemo(() => {
    let products = demoProducts;

    // Filter by tab
    if (activeTab !== 'all') {
      products = products.filter((p) => p.type === activeTab);
    }

    // Filter by search
    if (search.trim()) {
      const q = search.toLowerCase();
      products = products.filter(
        (p) =>
          p.title.toLowerCase().includes(q) ||
          p.description.toLowerCase().includes(q)
      );
    }

    // Sort
    return sortProducts(products, sortBy);
  }, [activeTab, search, sortBy]);

  return (
    <div className="page-enter space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-[var(--text-primary)]">
            Products
          </h1>
        </div>
        <Button variant="primary" icon={<Plus className="w-4 h-4" />}>
          Add Product
        </Button>
      </div>

      {/* Search + Sort */}
      <div className="flex flex-col sm:flex-row gap-3">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-[var(--text-tertiary)]" />
          <input
            type="text"
            placeholder="Search products..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="w-full pl-10 pr-4 py-2.5 text-sm rounded-lg border border-[var(--border-default)] bg-[var(--bg-surface)] text-[var(--text-primary)] placeholder-[var(--text-tertiary)] focus:outline-none focus:ring-2 focus:ring-[var(--accent)] focus:border-transparent transition-all"
          />
        </div>
        <div className="relative">
          <button
            onClick={() => setSortOpen(!sortOpen)}
            className="flex items-center gap-2 px-4 py-2.5 text-sm rounded-lg border border-[var(--border-default)] bg-[var(--bg-surface)] text-[var(--text-primary)] hover:bg-[var(--bg-elevated)] transition-colors cursor-pointer"
          >
            <span>{sortOptions.find((o) => o.value === sortBy)?.label}</span>
            <ChevronDown className="w-4 h-4 text-[var(--text-secondary)]" />
          </button>
          {sortOpen && (
            <div className="absolute right-0 top-full mt-1 z-20 w-48 rounded-lg border border-[var(--border-default)] bg-[var(--bg-surface)] shadow-lg py-1">
              {sortOptions.map((option) => (
                <button
                  key={option.value}
                  onClick={() => {
                    setSortBy(option.value);
                    setSortOpen(false);
                  }}
                  className={`w-full text-left px-4 py-2 text-sm transition-colors cursor-pointer ${
                    sortBy === option.value
                      ? 'bg-[var(--accent-subtle)] text-[var(--accent)]'
                      : 'text-[var(--text-primary)] hover:bg-[var(--bg-elevated)]'
                  }`}
                >
                  {option.label}
                </button>
              ))}
            </div>
          )}
        </div>
      </div>

      {/* Tabs */}
      <Tabs tabs={productTabs} activeTab={activeTab} onChange={setActiveTab} />

      {/* Product Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {filteredProducts.map((product) => {
          const Icon = typeIcons[product.type];
          const isPublished = publishedState[product.id] ?? product.published;

          return (
