                    <div
                      key={product.id}
                      className="rounded-xl border border-[var(--border-default)] p-3.5 hover:shadow-sm transition-shadow"
                    >
                      <div className="flex items-center justify-between gap-3">
                        <div className="min-w-0 flex-1">
                          <p className="text-sm font-semibold text-[var(--text-primary)] truncate">
                            {product.title}
                          </p>
                          <p className="text-xs text-[var(--text-secondary)] mt-0.5">
                            {product.type.charAt(0).toUpperCase() +
                              product.type.slice(1)}
                          </p>
                        </div>
                        <button
                          className="shrink-0 px-3 py-1.5 rounded-lg text-xs font-semibold text-white transition-opacity hover:opacity-90"
                          style={{ backgroundColor: primaryColor }}
                        >
                          ${product.price}
                        </button>
                      </div>
                    </div>
                  ))}
                </div>

                {/* Store Footer */}
                <div className="mt-6 flex items-center justify-center gap-1.5 text-xs text-[var(--text-tertiary)]">
                  <ShoppingBag className="w-3 h-3" />
                  <span>Powered by Stan</span>
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* Right: Customization */}
        <div className="space-y-6">
          {/* Template Selector */}
          <Card padding="md">
            <h3 className="text-sm font-semibold text-[var(--text-primary)] mb-4">
              Store Template
            </h3>
            <div className="grid grid-cols-2 gap-3">
              {templates.map((template) => {
                const isActive = template.id === selectedTemplate;
                return (
                  <button
                    key={template.id}
                    onClick={() => setSelectedTemplate(template.id)}
                    className={`relative rounded-xl border-2 p-3 text-left transition-all cursor-pointer ${
                      isActive
                        ? 'border-[var(--accent)] bg-[var(--accent-subtle)]'
                        : 'border-[var(--border-default)] hover:border-[var(--border-strong)]'
                    }`}
                  >
                    {/* Mini Preview */}
                    <div
                      className="h-20 rounded-lg mb-2.5 flex items-center justify-center overflow-hidden"
                      style={{ backgroundColor: template.preview.bg }}
                    >
                      <div className="space-y-1 w-3/4">
                        <div
                          className="h-3 rounded-full w-1/2 mx-auto"
                          style={{
                            backgroundColor: template.preview.accent,
                            opacity: 0.7,
                          }}
                        />
                        <div className="h-2 rounded-full w-3/4 mx-auto bg-gray-300/50" />
                        <div className="h-2 rounded-full w-2/3 mx-auto bg-gray-300/30" />
                        <div className="flex gap-1 mt-2 justify-center">
                          <div
                            className="h-6 w-6 rounded"
                            style={{
                              backgroundColor: template.preview.accent,
                              opacity: 0.3,
                            }}
                          />
                          <div
                            className="h-6 w-6 rounded"
                            style={{
                              backgroundColor: template.preview.accent,
                              opacity: 0.2,
                            }}
                          />
                          <div
                            className="h-6 w-6 rounded"
                            style={{
                              backgroundColor: template.preview.accent,
                              opacity: 0.15,
                            }}
                          />
                        </div>
                      </div>
                    </div>
                    <p className="text-sm font-medium text-[var(--text-primary)]">
                      {template.name}
                    </p>
                    <p className="text-xs text-[var(--text-secondary)]">
                      {template.description}
                    </p>
                    {isActive && (
                      <div className="absolute top-2 right-2 w-5 h-5 rounded-full bg-[var(--accent)] flex items-center justify-center">
                        <Check className="w-3 h-3 text-white" />
                      </div>
                    )}
                  </button>
                );
              })}
            </div>
          </Card>

          {/* Color Picker */}
          <Card padding="md">
            <h3 className="text-sm font-semibold text-[var(--text-primary)] mb-4">
              Primary Color
            </h3>
            <div className="flex flex-wrap gap-3">
              {colorSwatches.map((swatch) => {
                const isActive = swatch.value === primaryColor;
                return (
                  <button
                    key={swatch.value}
                    onClick={() => setPrimaryColor(swatch.value)}
                    className={`relative w-10 h-10 rounded-full transition-all cursor-pointer ${
                      isActive
                        ? 'ring-2 ring-offset-2 ring-[var(--accent)]'
                        : 'hover:scale-110'
                    }`}
                    style={{ backgroundColor: swatch.value }}
                    title={swatch.name}
                  >
                    {isActive && (
                      <Check className="w-4 h-4 text-white absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2" />
                    )}
                  </button>
                );
              })}
            </div>
          </Card>

          {/* Font Selector */}
          <Card padding="md">
            <h3 className="text-sm font-semibold text-[var(--text-primary)] mb-4">
              Font Family
            </h3>
            <div className="space-y-2">
              {fontOptions.map((font) => {
                const isActive = font.name === selectedFont;
                return (
                  <button
                    key={font.name}
                    onClick={() => setSelectedFont(font.name)}
                    className={`w-full flex items-center justify-between px-4 py-3 rounded-lg border transition-all cursor-pointer ${
                      isActive
                        ? 'border-[var(--accent)] bg-[var(--accent-subtle)]'
                        : 'border-[var(--border-default)] hover:border-[var(--border-strong)]'
                    }`}
                  >
                    <span
                      className="text-sm text-[var(--text-primary)]"
                      style={{ fontFamily: font.family }}
                    >
                      {font.name}
                    </span>
                    <span
                      className="text-lg text-[var(--text-secondary)]"
                      style={{ fontFamily: font.family }}
                    >
                      Aa
                    </span>
                  </button>
                );
              })}
            </div>
          </Card>

          {/* Save */}
          <Button
            variant="primary"
            size="lg"
            icon={<Save className="w-4 h-4" />}
            className="w-full"
          >
            Save Changes
          </Button>
        </div>
      </div>
    </div>
  );
}
